import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Card, Input, Badge, Avatar, Checkbox, Select, icon } from 'decantr/components';

code.example:
function SubscriberList({ subscribers: initialSubs = [], tiers = [] }) {
  const { div, table, thead, tbody, tr, th, td, span } = tags;
  const [search, setSearch] = createSignal('');
  const [tierFilter, setTierFilter] = createSignal('all');
  const [selected, setSelected] = createSignal([]);
  const [sortBy, setSortBy] = createSignal('joined');
  const [sortDir, setSortDir] = createSignal('desc');

  const filtered = () => {
    let subs = initialSubs;
    if (search()) subs = subs.filter(s => s.name.toLowerCase().includes(search().toLowerCase()) || s.email.toLowerCase().includes(search().toLowerCase()));
    if (tierFilter() !== 'all') subs = subs.filter(s => s.tierId === tierFilter());
    return subs.sort((a, b) => {
      const dir = sortDir() === 'asc' ? 1 : -1;
      if (sortBy() === 'joined') return dir * (new Date(b.joinedAt) - new Date(a.joinedAt));
      if (sortBy() === 'lifetime') return dir * (b.lifetimeValue - a.lifetimeValue);
      return 0;
    });
  };

  const toggleAll = () => setSelected(selected().length === filtered().length ? [] : filtered().map(s => s.id));
  const toggleOne = (id) => setSelected(selected().includes(id) ? selected().filter(i => i !== id) : [...selected(), id]);

  const SortHeader = ({ col, label }) =>
    th({ class: css('_textsm _fontmedium _fgmuted _p3 _tl _cursor[pointer]'), onclick: () => {
      if (sortBy() === col) setSortDir(sortDir() === 'asc' ? 'desc' : 'asc');
      else { setSortBy(col); setSortDir('desc'); }
    }},
      div({ class: css('_flex _aic _gap1') },
        label,
        sortBy() === col ? icon(sortDir() === 'asc' ? 'chevron-up' : 'chevron-down', { size: '14' }) : null
      )
    );

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _gap4 _aic _jcsb _flexwrap') },
      div({ class: css('_flex _gap3 _aic') },
        div({ class: css('_relative') },
          icon('search', { size: '18', class: css('_absolute _left3 _top[50%] _translate[0,-50%] _fgmuted') }),
          Input({ value: search(), onchange: (e) => setSearch(e.target.value), placeholder: 'Search subscribers...', class: css('_pl10 _w[280px]') })
        ),
        Select({ value: tierFilter(), onchange: (e) => setTierFilter(e.target.value), options: [{ value: 'all', label: 'All Tiers' }, ...tiers.map(t => ({ value: t.id, label: t.name }))] })
      ),
      div({ class: css('_flex _gap2') },
        selected().length > 0 ? [
          Button({ variant: 'outline', size: 'sm' }, icon('mail', { size: '14', class: css('_mr1') }), 'Message'),
          Button({ variant: 'outline', size: 'sm' }, icon('download', { size: '14', class: css('_mr1') }), 'Export')
        ] : [
          Button({ variant: 'outline', size: 'sm' }, icon('download', { size: '14', class: css('_mr1') }), 'Export All')
        ]
      )
    ),
    Card({ class: css('studio-card _overflow[hidden]') },
      table({ class: css('_wfull') },
        thead({ class: css('_bgmuted/5 _borderB') },
          tr({},
            th({ class: css('_p3 _w10') }, Checkbox({ checked: selected().length === filtered().length && filtered().length > 0, onchange: toggleAll })),
            th({ class: css('_textsm _fontmedium _fgmuted _p3 _tl') }, 'Subscriber'),
            SortHeader({ col: 'tier', label: 'Tier' }),
            SortHeader({ col: 'joined', label: 'Joined' }),
            th({ class: css('_textsm _fontmedium _fgmuted _p3 _tl') }, 'Status'),
            SortHeader({ col: 'lifetime', label: 'Lifetime' }),
            th({ class: css('_p3 _w16') }, '')
          )
        ),
        tbody({},
          ...filtered().map(sub =>
            tr({ class: css('_borderB _last:borderB0 _hover:bgmuted/5 _trans') },
              td({ class: css('_p3') }, Checkbox({ checked: selected().includes(sub.id), onchange: () => toggleOne(sub.id) })),
              td({ class: css('_p3') },
                div({ class: css('_flex _aic _gap3') },
                  Avatar({ src: sub.avatar, name: sub.name, size: 'sm' }),
                  div({},
                    span({ class: css('_fontmedium') }, sub.name),
                    div({ class: css('_textsm _fgmuted') }, sub.email)
                  )
                )
              ),
              td({ class: css('_p3') },
                div({ class: css('_flex _aic _gap2') },
                  div({ class: css('_w2 _h2 _r[4px]'), style: `background:${sub.tierColor}` }),
                  span({ class: css('_textsm') }, sub.tierName)
                )
              ),
              td({ class: css('_p3 _textsm _fgmuted') }, new Date(sub.joinedAt).toLocaleDateString()),
              td({ class: css('_p3') },
                Badge({ variant: sub.status === 'active' ? 'default' : 'secondary', size: 'sm' },
                  sub.status === 'active' ? 'Active' : 'Cancelled'
                )
              ),
              td({ class: css('_p3 _textsm _fontmedium') }, '$', sub.lifetimeValue.toFixed(2)),
              td({ class: css('_p3') },
                Button({ variant: 'ghost', size: 'sm' }, icon('more-horizontal', { size: '16' }))
              )
            )
          )
        )
      )
    ),
    div({ class: css('_flex _jcsb _aic _textsm _fgmuted') },
      span({}, filtered().length, ' subscribers'),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'outline', size: 'sm', disabled: true }, 'Previous'),
        Button({ variant: 'outline', size: 'sm' }, 'Next')
      )
    )
  );
}

