function CompactSubscriberList({ subscribers }) {
  const { div, span } = tags;

  return div({ class: css('_grid _gc1 _md:gc2 _gap4') },
    ...subscribers.map(sub =>
      Card({ class: css('studio-card _p4 _flex _aic _gap4') },
        Avatar({ src: sub.avatar, name: sub.name }),
        div({ class: css('_flex1') },
          div({ class: css('_flex _aic _gap2 _mb1') },
            span({ class: css('_fontmedium') }, sub.name),
            Badge({ variant: 'secondary', size: 'xs' }, sub.tierName)
          ),
          span({ class: css('_textsm _fgmuted') }, 'Joined ', new Date(sub.joinedAt).toLocaleDateString())
        ),
        icon('chevron-right', { class: css('_fgmuted') })
      )
    )
  );
}

